// pythonReferenceResults maps depth -> reorg probability from the Python reference.
var pythonReferenceResults = map[int]float64{
	5:   1.58182730260265891863e-03,
	10:  1.67515743138728720072e-04,
	15:  2.80696481196116546684e-06,
	20:  6.84359796410981096872e-08,
	25:  1.46218662028857760238e-09,
	30:  4.62723254179747158594e-12,
	40:  3.53912692038794048900e-17,
	50:  1.37790735432279053542e-20,
	75:  2.40782990048672131651e-24,
	100: 3.21616912956779552478e-24,
}

func TestCalcValidatorProb_PythonReference(t *testing.T) {
	req := require.New(t)
	chain := pythonReferenceChain
	currentEpoch := len(chain) - 1

	for depth, wantProb := range pythonReferenceResults {
		targetEpoch := currentEpoch - depth
		gotProb := CalcValidatorProb(chain, testFinality, 5.0, 0.3, currentEpoch, targetEpoch)

		relErr := math.Abs(gotProb-wantProb) / math.Abs(wantProb)
		req.LessOrEqualf(relErr, 1e-12,
			"depth=%d: got %.15e, want %.15e (relErr=%.3e)", depth, gotProb, wantProb, relErr)
	}
}

func TestCalcValidatorProb_HealthyChain(t *testing.T) {
	req := require.New(t)

	// A perfectly healthy chain with 5 blocks per epoch should achieve
	// 2^-30 finality well within 30 epochs
	chain := make([]int, 905)
	for i := range chain {
		chain[i] = 5
	}
	currentEpoch := len(chain) - 1
	guarantee := math.Pow(2, -30)

	prob30 := CalcValidatorProb(chain, testFinality, 5.0, 0.3, currentEpoch, currentEpoch-30)
	req.Less(prob30, guarantee, "healthy chain at depth 30 should be below 2^-30")

	prob5 := CalcValidatorProb(chain, testFinality, 5.0, 0.3, currentEpoch, currentEpoch-5)
	req.Greater(prob5, prob30, "shallower depth should have higher reorg probability")
}

func TestCalcValidatorProb_DegradedChain(t *testing.T) {
	req := require.New(t)

	// A degraded chain with only 2 blocks per epoch should have much worse
	// finality than a healthy chain at the same depth
	chain := make([]int, 905)
	for i := range chain {
		chain[i] = 2
	}
	currentEpoch := len(chain) - 1
	guarantee := math.Pow(2, -30)

	prob30 := CalcValidatorProb(chain, testFinality, 5.0, 0.3, currentEpoch, currentEpoch-30)
	req.GreaterOrEqual(prob30, guarantee, "degraded chain at depth 30 should NOT achieve 2^-30")
}

func TestFindThresholdDepth_HealthyChain(t *testing.T) {
	req := require.New(t)

	chain := make([]int, 905)
	for i := range chain {
		chain[i] = 5
	}
	guarantee := math.Pow(2, -30)

	depth := FindThresholdDepth(chain, testFinality, 5.0, 0.3, guarantee)
	req.Greater(depth, 0, "healthy chain should find a threshold")
	req.Less(depth, 35, "healthy chain should finalize well before depth 35")
}

func TestFindThresholdDepth_DegradedChain(t *testing.T) {
	req := require.New(t)

	// All-2s chain is too degraded to achieve 2^-30 within the bisect
	// search range (BisectHigh=450), so threshold is not found
	chain := make([]int, 905)
	for i := range chain {
		chain[i] = 2
	}
	guarantee := math.Pow(2, -30)

	depth := FindThresholdDepth(chain, testFinality, 5.0, 0.3, guarantee)
	req.Equal(-1, depth, "severely degraded chain should not find threshold within search range")
}

func TestFindThresholdDepth_MildlyDegradedChain(t *testing.T) {
	req := require.New(t)

	// All-3s chain is degraded but should still find a threshold,
	// just deeper than a healthy chain
	chain := make([]int, 905)
	for i := range chain {
		chain[i] = 3
	}
	guarantee := math.Pow(2, -30)

	depth := FindThresholdDepth(chain, testFinality, 5.0, 0.3, guarantee)
	req.Greater(depth, 35, "mildly degraded chain should require more depth than healthy")
	req.Less(depth, BisectHigh, "mildly degraded chain should still find a threshold")
}
